using System;
using System.Collections.Generic;
using System.Xml;

public class XmlConfigParser
{
    public Dictionary<string, string> ParseXmlConfig(string xmlFilePath)
    {
        Dictionary<string, string> configSettings = new Dictionary<string, string>();
        XmlReaderSettings settings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD
        };

        using (XmlReader reader = XmlReader.Create(xmlFilePath, settings))
        {
            XmlDocument document = new XmlDocument();
            document.Load(reader);

            XmlNodeList nodes = document.SelectNodes("//setting");
            foreach (XmlNode node in nodes)
            {
                if (node.Attributes != null)
                {
                    string key = node.Attributes["name"]?.Value;
                    string value = node.Attributes["value"]?.Value;
                    if (key != null && value != null)
                    {
                        configSettings.Add(key, value);
                    }
                }
            }
        }
        return configSettings;
    }
}